import zlib, base64, json
from functools import lru_cache
from typing import Optional

_DATA = ""

@lru_cache(maxsize=1)
def _load() -> dict:
    return json.loads(zlib.decompress(base64.b64decode(_DATA)).decode('utf-8'))

def get_description(hs_code: str) -> Optional[dict]:
    """
    Return dict with 'th' and 'en' descriptions for an 8-digit HS code.
    Tries exact match, then various normalizations.
    Returns None if not found.
    """
    db = _load()
    # Try as-is
    if hs_code in db:
        return db[hs_code]
    # Strip spaces
    clean = hs_code.replace(" ", "").replace(".", "")
    # Pad to 8 digits
    clean = clean.ljust(8, "0")[:8]
    if clean in db:
        return db[clean]
    # Try with leading space (original format)
    spaced = " " + clean
    if spaced in db:
        return db[spaced]
    return None

def get_description_th(hs_code: str) -> Optional[str]:
    r = get_description(hs_code)
    return r["th"] if r else None

def get_description_en(hs_code: str) -> Optional[str]:
    r = get_description(hs_code)
    return r["en"] if r else None

def stats() -> dict:
    db = _load()
    return {"total_codes": len(db), "source": "AHTN Protocol 2022 (กรมศุลกากรไทย)"}
